// File: src/stores/customerStore.ts
import { defineStore } from 'pinia';
import type {
  CustomerSession,
  Table,
  Area,
  Branch,
  MenuItem,
  MenuCategory,
  CartItem,
  Order,
  ServiceRequest,
  Feedback,
  SubCategory
} from '@/types/customer';
import { customerApiImpl } from '@/services/customerApi';
import { computeTotals } from '@/utils/packageRules';
import { isValidUUID } from '@/utils/validators';

export interface Notification {
  id: string;
  message: string;
  type: 'info' | 'success' | 'warning' | 'error';
}

export const useCustomerStore = defineStore('customer', {
  state: () => ({
    // Session
    session: null as CustomerSession | null,
    isAuthenticated: false, // unlocked by staff passcode

    // Branch
    branches: [] as Branch[],
    selectedBranchId: null as string | null,

    // Area & Table
    areas: [] as Area[],
    selectedAreaId: null as string | null,
    tables: [] as Table[],
    selectedTable: null as Table | null,

    // Menu
    menuData: [] as MenuCategory[],
    selectedCategory: null as MenuCategory | null,
    selectedSubcategory: null as SubCategory | null,

    // Cart
    cart: [] as CartItem[],

    // Orders
    orders: [] as Order[],
    currentOrder: null as Order | null,

    // Service Requests
    serviceRequests: [] as ServiceRequest[],

    // Feedback
    feedback: null as Feedback | null,

    // UI State
    loading: false,
    currentView: 'home' as 'home' | 'menu' | 'cart' | 'history' | 'feedback',
    notifications: [] as Notification[],
    searchQuery: '',
    currentLanguage: 'vi' as 'vi' | 'en' | 'ja'
  }),

  actions: {
    // NV1: Authentication & Table Selection
    async authenticateStaff(passcode: string): Promise<boolean> {
      const res = await customerApiImpl.authenticateStaff(passcode);
      this.isAuthenticated = res.success;
      return res.success;
    },

    async loadBranches(): Promise<Branch[]> {
      const branches = await customerApiImpl.getBranches();
      this.branches = branches;
      return branches;
    },

    async loadAreas(branchId?: string): Promise<Area[]> {
      const areas = await customerApiImpl.getAreas(branchId ?? this.selectedBranchId ?? undefined);
      this.areas = areas;
      return areas;
    },

    async loadTables(areaId: string): Promise<Table[]> {
      const tables = await customerApiImpl.getTables(areaId);
      this.tables = tables;
      return tables;
    },

    async selectTable(tableId: string): Promise<boolean> {
      const res = await customerApiImpl.selectTable(tableId);
      if (res.success) {
        const table = this.tables.find(t => t.id === tableId);
        if (table) {
          this.selectedTable = table;
        }
        return true;
      }
      return false;
    },

    async confirmTable(): Promise<void> {
      if (!this.selectedTable) return;

      const newSession: CustomerSession = {
        id: `sess-${Date.now()}`,
        tableId: this.selectedTable.id,
        tableNumber: this.selectedTable.number,
        areaId: this.selectedTable.areaId,
        areaName: this.areas.find(a => a.id === this.selectedTable?.areaId)?.name || 'Khu vực',
        staffId: 'staff-uuid-001',
        startedAt: new Date(),
        status: 'active'
      };

      const session = await customerApiImpl.confirmTable(newSession);
      this.session = session;
      this.currentView = 'menu';

      // Persist session to localStorage for active session recovery
      localStorage.setItem('nguucat_customer_session', JSON.stringify(session));
      localStorage.setItem('nguucat_customer_auth', 'true');
      if (this.selectedTable) {
        localStorage.setItem('nguucat_customer_table', JSON.stringify(this.selectedTable));
      }
    },

    // NV2: Menu & Add to Cart
    async loadMenu(): Promise<void> {
      // The store exposes the same nested shape that
      // `src/data/menuData.ts` ships (categories → subcategories →
      // items). The mock file uses fake auto-counter ids
      // (`bf1390-1`, `lunch-16`, …); the live Supabase `menu_items`
      // rows have real UUIDs. We deep-clone the template, then walk
      // it and substitute each leaf item's `id` / `price` /
      // `price_display` with the DB values matched on `name`.
      //
      // Some names appear multiple times in the DB (e.g. `7UP` has
      // both a 35.000đ "à la carte" row and a 0đ "in-package" row).
      // Tie-break on price: prefer the DB row whose price matches the
      // mock item's price; if neither matches, take the first.
      const dbItems = await customerApiImpl.getRawMenuItems()
      const byName = new Map<string, Array<{ id: string; price: number; price_display?: string }>>()
      for (const it of dbItems) {
        if (!it?.name || !it?.id) continue
        const arr = byName.get(it.name) ?? []
        arr.push({ id: it.id, price: it.price, price_display: it.price_display })
        byName.set(it.name, arr)
      }
      const template = await customerApiImpl.getMenuTemplate()
      const transformed = JSON.parse(JSON.stringify(template)) as MenuCategory[]
      const pickReal = (
        name: string,
        mockPrice: number,
      ): { id: string; price: number; price_display?: string } | undefined => {
        const arr = byName.get(name)
        if (!arr || arr.length === 0) return undefined
        const exact = arr.find((r) => r.price === mockPrice)
        if (exact) return exact
        // Prefer non-zero when mock is zero, and zero when mock is non-zero.
        const dir = arr.find((r) => (mockPrice === 0 ? r.price === 0 : r.price > 0))
        return dir ?? arr[0]
      }
      const walk = (items?: MenuItem[]) => {
        if (!items) return
        for (const it of items) {
          const real = pickReal(it.name, Number(it.price ?? 0))
          if (real) {
            it.id = real.id
            it.price = real.price
            if (real.price_display) it.price_display = real.price_display
          } else {
            // No DB match found — mark as unavailable so it cannot be
            // added to cart (its mock id is not a valid UUID).
            it.is_available = false
          }
        }
      }
      for (const cat of transformed) {
        if (cat.items) walk(cat.items)
        if (cat.subcategories) {
          for (const sub of cat.subcategories) {
            walk(sub.items)
          }
        }
      }
      this.menuData = transformed
      if (transformed.length > 0) {
        this.selectedCategory = transformed[0]
        if (transformed[0].subcategories && transformed[0].subcategories.length > 0) {
          this.selectedSubcategory = transformed[0].subcategories[0]
        }
      }
    },

    selectCategory(categoryId: string): void {
      const cat = this.menuData.find(c => c.id === categoryId);
      if (cat) {
        this.selectedCategory = cat;
        if (cat.subcategories && cat.subcategories.length > 0) {
          this.selectedSubcategory = cat.subcategories[0];
        } else {
          this.selectedSubcategory = null;
        }
      }
    },

    selectSubcategory(subcategoryId: string): void {
      if (this.selectedCategory?.subcategories) {
        const sub = this.selectedCategory.subcategories.find(s => s.id === subcategoryId);
        if (sub) {
          this.selectedSubcategory = sub;
        }
      }
    },

    addToCart(item: MenuItem, quantity: number = 1): void {
      const existing = this.cart.find(
        c => c.menuItemId === item.id && (c.note ?? '') === '',
      );
      if (existing) {
        existing.quantity += quantity;
      } else {
        this.cart.push({
          menuItemId: item.id,
          name: item.name,
          unit: item.unit,
          price: item.price,
          price_display: item.price_display,
          quantity: quantity,
          note: ''
        });
      }
    },

    updateCartItem(itemId: string, quantity: number): void {
      const existing = this.cart.find(c => c.menuItemId === itemId);
      if (existing) {
        existing.quantity = quantity;
        if (existing.quantity <= 0) {
          this.removeFromCart(itemId);
        }
      }
    },

    updateCartItemNote(itemId: string, note: string): void {
      const existing = this.cart.find(c => c.menuItemId === itemId);
      if (existing) {
        existing.note = note;
      }
    },

    removeFromCart(itemId: string): void {
      this.cart = this.cart.filter(c => c.menuItemId !== itemId);
    },

    clearCart(): void {
      this.cart = [];
    },

    // Remove all cart items whose menuItemId is not a valid UUID.
    // Returns the names of removed items so the caller can notify the user.
    removeInvalidCartItems(): string[] {
      const invalid = this.cart.filter(c => !isValidUUID(c.menuItemId));
      this.cart = this.cart.filter(c => isValidUUID(c.menuItemId));
      return invalid.map(c => c.name);
    },

    // NV3: Service Request
    async submitServiceRequest(requestType: string, content?: string): Promise<void> {
      if (!this.session) return;

      const request: ServiceRequest = {
        id: `req-${Date.now()}`,
        sessionId: this.session.id,
        tableNumber: this.session.tableNumber,
        type: requestType as any,
        content: content || '',
        status: 'created',
        createdAt: new Date()
      };

      const result = await customerApiImpl.submitServiceRequest(request);
      this.serviceRequests.push(result);
      this.addNotification(`Đã gửi yêu cầu: ${this.translateRequestType(requestType)}`, 'success');
    },

    async cancelServiceRequest(requestId: string): Promise<void> {
      await customerApiImpl.updateServiceRequest(requestId, 'cancelled');
      const req = this.serviceRequests.find(r => r.id === requestId);
      if (req) {
        req.status = 'cancelled';
      }
      this.addNotification('Đã hủy yêu cầu phục vụ', 'info');
    },

    // NV4: Cart & Order
    async confirmOrder(): Promise<Order> {
      if (!this.session || this.cart.length === 0) {
        throw new Error('Giỏ hàng trống hoặc phiên làm việc chưa bắt đầu');
      }

      // Validate all cart items for UUID format
      const invalidItems = this.cart.filter(item => !isValidUUID(item.menuItemId));
      if (invalidItems.length > 0) {
        const names = invalidItems.map(i => i.name).join(', ');
        throw new Error(`Có ${invalidItems.length} món không hợp lệ trong giỏ hàng: ${names}`);
      }

      const subtotal = this.cartTotal;
      const charge = this.serviceCharge;
      const vatVal = this.vat;
      const grand = this.grandTotal;

      const order: Order = {
        id: `ord-${Date.now()}`,
        sessionId: this.session.id,
        tableNumber: this.session.tableNumber,
        items: [...this.cart],
        subtotal,
        serviceCharge: charge,
        vat: vatVal,
        discount: 0,
        total: grand,
        status: 'draft',
        createdAt: new Date()
      };

      const confirmedOrder = await customerApiImpl.createOrder(order);
      confirmedOrder.status = 'confirmed';
      this.orders.push(confirmedOrder);
      this.clearCart();
      this.addNotification('Đã gửi món vào bếp thành công!', 'success');
      return confirmedOrder;
    },

    async cancelOrder(orderId: string): Promise<void> {
      // Typically orders cannot be canceled after confirmation from tablet,
      // but let's provide client side action
      this.orders = this.orders.filter(o => o.id !== orderId);
      this.addNotification('Đã hủy order', 'info');
    },

    // NV5: History & Payment
    async loadOrderHistory(): Promise<Order[]> {
      if (!this.session) return [];
      const history = await customerApiImpl.getOrderHistory(this.session.id);
      this.orders = history;
      return history;
    },

    async requestPayment(): Promise<void> {
      if (!this.session) return;
      await customerApiImpl.requestPayment(this.session.id);
      this.session.status = 'waiting_payment';
      this.addNotification('Đã gửi yêu cầu thanh toán. Vui lòng đợi nhân viên.', 'success');
    },

    async requestInvoice(): Promise<void> {
      if (!this.session) return;
      await customerApiImpl.requestInvoice(this.session.id);
      this.addNotification('Đã gửi yêu cầu xuất hóa đơn đỏ.', 'success');
    },

    async submitFeedback(feedbackData: Omit<Feedback, 'id' | 'sessionId' | 'createdAt'>): Promise<void> {
      if (!this.session) return;

      const newFeedback: Feedback = {
        id: `fb-${Date.now()}`,
        sessionId: this.session.id,
        rating: feedbackData.rating,
        criteria: feedbackData.criteria,
        comment: feedbackData.comment || '',
        createdAt: new Date()
      };

      const result = await customerApiImpl.submitFeedback(newFeedback);
      this.feedback = result;
      this.addNotification('Cảm ơn đóng góp ý kiến của quý khách!', 'success');
    },

    // Session Management
    async endSession(): Promise<void> {
      if (this.session) {
        await customerApiImpl.releaseTable(this.session.id);
      }
      this.resetState();
    },

    resetState(): void {
      this.session = null;
      this.isAuthenticated = false;
      this.selectedBranchId = null;
      this.selectedAreaId = null;
      this.selectedTable = null;
      this.cart = [];
      this.orders = [];
      this.serviceRequests = [];
      this.feedback = null;
      this.currentView = 'home';
      this.notifications = [];
    },

    // UI Helpers
    addNotification(message: string, type: 'info' | 'success' | 'warning' | 'error' = 'info'): void {
      const id = `notif-${Date.now()}`;
      this.notifications.push({ id, message, type });
      setTimeout(() => {
        this.notifications = this.notifications.filter(n => n.id !== id);
      }, 4000);
    },

    translateRequestType(type: string): string {
      const types: Record<string, string> = {
        tissue: 'Lấy khăn giấy',
        bowl: 'Lấy chén bát sạch',
        sauce: 'Lấy nước chấm',
        ice: 'Lấy đá thêm',
        grill_change: 'Thay vỉ nướng',
        charcoal_change: 'Thêm than',
        request_bill: 'Thanh toán hóa đơn',
        call_waiter: 'Gọi nhân viên',
        other: 'Yêu cầu khác'
      };
      return types[type] || type;
    }
  },

  getters: {
    /**
     * Cart subtotal AFTER all rules: package-pricing (zero when in-pkg)
     * + lunch 50% discount are both baked into the stored `price`
     * field at add-to-cart time via the shared `@/utils/packageRules`
     * engine. So `cartTotal` collapses to `price * quantity`. Service
     * charge / VAT use the shared `computeTotals()` so the customer
     * and cashier previews agree to the đồng.
     */
    cartTotal: (state) => {
      return state.cart.reduce(
        (sum, item) => sum + Number(item.price ?? 0) * Number(item.quantity ?? 1),
        0,
      )
    },
    cartItemCount: (state) => {
      return state.cart.reduce((sum, item) => sum + item.quantity, 0);
    },
    serviceCharge(): number {
      return computeTotals(this.cartTotal).serviceCharge
    },
    vat(): number {
      return computeTotals(this.cartTotal).vat
    },
    grandTotal(): number {
      return computeTotals(this.cartTotal).total
    },
    activeServiceRequests: (state) => {
      return state.serviceRequests.filter(r => r.status !== 'completed' && r.status !== 'cancelled');
    },
    orderHistory: (state) => {
      return state.orders;
    }
  }
});

// File: src/composables/useCustomerSession.ts
import { ref, computed, onMounted } from 'vue';
import { useCustomerStore } from '@/stores/customerStore';
import type { CustomerSession, Table } from '@/types/customer';

export function useCustomerSession() {
  const store = useCustomerStore();

  const SESSION_KEY = 'nguucat_customer_session';
  const AUTH_KEY = 'nguucat_customer_auth';
  const TABLE_KEY = 'nguucat_customer_table';
  const CART_KEY = 'nguucat_customer_cart';

  const session = computed(() => store.session);
  const isAuthenticated = computed(() => store.isAuthenticated);
  const selectedTable = computed(() => store.selectedTable);

  function saveSessionToLocalStorage() {
    if (store.session) {
      localStorage.setItem(SESSION_KEY, JSON.stringify(store.session));
    } else {
      localStorage.removeItem(SESSION_KEY);
    }

    localStorage.setItem(AUTH_KEY, String(store.isAuthenticated));

    if (store.selectedTable) {
      localStorage.setItem(TABLE_KEY, JSON.stringify(store.selectedTable));
    } else {
      localStorage.removeItem(TABLE_KEY);
    }

    localStorage.setItem(CART_KEY, JSON.stringify(store.cart));
  }

  function restoreSessionFromLocalStorage() {
    try {
      const savedSession = localStorage.getItem(SESSION_KEY);
      const savedAuth = localStorage.getItem(AUTH_KEY);
      const savedTable = localStorage.getItem(TABLE_KEY);
      const savedCart = localStorage.getItem(CART_KEY);

      if (savedAuth === 'true') {
        store.isAuthenticated = true;
      }

      if (savedTable) {
        store.selectedTable = JSON.parse(savedTable);
      }

      if (savedSession) {
        const parsedSession = JSON.parse(savedSession);
        // Revive date objects
        parsedSession.startedAt = new Date(parsedSession.startedAt);
        store.session = parsedSession;
        store.currentView = 'menu';
      }

      if (savedCart) {
        store.cart = JSON.parse(savedCart);
      }
    } catch (e) {
      console.error('Failed to restore customer session from localStorage:', e);
      clearSession();
    }
  }

  function startSession(table: Table, areaName: string) {
    store.selectedTable = table;
    store.isAuthenticated = true;

    const newSession: CustomerSession = {
      id: `sess-${Date.now()}`,
      tableId: table.id,
      tableNumber: table.number,
      areaId: table.areaId,
      areaName: areaName,
      staffId: 'staff-uuid-001',
      startedAt: new Date(),
      status: 'active'
    };

    store.session = newSession;
    store.currentView = 'menu';
    saveSessionToLocalStorage();
  }

  function clearSession() {
    store.resetState();
    localStorage.removeItem(SESSION_KEY);
    localStorage.removeItem(AUTH_KEY);
    localStorage.removeItem(TABLE_KEY);
    localStorage.removeItem(CART_KEY);
  }

  // Monitor and save changes whenever cart changes
  function syncCart() {
    localStorage.setItem(CART_KEY, JSON.stringify(store.cart));
  }

  return {
    session,
    isAuthenticated,
    selectedTable,
    startSession,
    clearSession,
    restoreSessionFromLocalStorage,
    saveSessionToLocalStorage,
    syncCart
  };
}

import { ref } from 'vue'
import { callEdgeFunction } from '@/utils/edge'

// NOTE: payload keys MUST match the Edge Function `add-order-item` contract
// which uses camelCase (`orderId`, `menuItemId`). See
// `supabase/functions/add-order-item/index.ts`.
export interface AddOrderItemPayload {
  orderId: string
  menuItemId: string
  quantity: number
  modifiers?: Record<string, unknown>[]
  note?: string
}

export interface AddOrderItemResponse {
  order_item_id: string
  line_total: number
  subtotal: number
  total: number
}

export function useOrder() {
  const loading = ref(false)
  const error = ref<string | null>(null)

  async function addItem(
    payload: AddOrderItemPayload,
  ): Promise<AddOrderItemResponse> {
    loading.value = true
    error.value = null
    try {
      return await callEdgeFunction<AddOrderItemPayload, AddOrderItemResponse>(
        'add-order-item',
        payload,
      )
    } catch (e) {
      error.value = e instanceof Error ? e.message : String(e)
      throw e
    } finally {
      loading.value = false
    }
  }

  return { loading, error, addItem }
}

import { ref } from 'vue'
import { supabase } from '@/lib/supabase'

export interface CheckoutResult {
  success: boolean
  bill_id: string
  invoice_id: string
  invoice_number: string
  grand_total: number
  linked_crm_surveys?: number
  subtotal?: number
  discount_total?: number
  voucher_discount?: number
  points_discount?: number
  service_charge_amount?: number
  vat_amount?: number
}

export interface CheckoutTotals {
  subtotal: number
  tier_discount: number
  voucher_discount: number
  points_discount: number
  total_discount: number
  net_before_tax: number
  service_charge_percent: number
  service_charge_amount: number
  vat_rate: number
  vat_amount: number
  grand_total: number
}

export interface CheckoutPreview {
  ok: boolean
  order?: Record<string, unknown>
  table?: Record<string, unknown>
  items?: Array<Record<string, unknown>>
  totals: CheckoutTotals
  voucher_valid: boolean
  error?: string
}

export function useCheckout() {
  const checkoutResult = ref<CheckoutResult | null>(null)
  const loading = ref(false)
  const error = ref<string | null>(null)

  /**
   * Preview the EXACT totals process_checkout will compute. Frontend display
   * matches the eventual bill byte-for-byte — no more 10% UI vs 8% DB drift.
   */
  async function previewCheckout(params: {
    branchId: string
    tableId: string
    orderId?: string
    voucherCode?: string
    pointsToRedeem?: number
    customerId?: string
  }): Promise<CheckoutPreview> {
    loading.value = true
    error.value = null
    try {
      const { data, error: err } = await supabase.rpc('hall_get_checkout_totals', {
        p_branch_id: params.branchId,
        p_table_id: params.tableId,
        p_order_id: params.orderId ?? null,
        p_voucher_code: params.voucherCode ?? null,
        p_points_to_use: params.pointsToRedeem ?? 0,
        p_customer_id: params.customerId ?? null,
      })
      if (err) throw err
      const row = (data ?? {}) as { ok?: boolean; error?: string } & Record<string, unknown>
      return {
        ok: row.ok === true,
        order: row.order as Record<string, unknown> | undefined,
        table: row.table as Record<string, unknown> | undefined,
        items: row.items as Array<Record<string, unknown>> | undefined,
        totals: row.totals as CheckoutTotals,
        voucher_valid: row.voucher_valid === true,
        error: row.error,
      }
    } catch (e: any) {
      error.value = e.message || String(e)
      throw e
    } finally {
      loading.value = false
    }
  }

  /**
   * Single-table summary for floor-plan / table-modal previews.
   * Caches by tableId to avoid re-querying when switching back.
   *
   * IMPORTANT: previously the cache never re-fetched after the first load,
   * which meant opening the same table-modal twice in a row would show
   * stale totals — and if the cashier rapidly opened A then B, the B total
   * would appear to "leak" with the previous A value because both views
   * shared the same Map. We now always force a re-fetch by default and
   * only honour the cache when the caller passes `useCache: true`.
   */
  const _tableCache = new Map<string, CheckoutPreview>()
  async function previewTableSummary(
    branchId: string,
    tableId: string,
    options: { useCache?: boolean } = {},
  ): Promise<CheckoutPreview> {
    if (options.useCache) {
      const cached = _tableCache.get(tableId)
      if (cached) return cached
    }
    const fresh = await previewCheckout({ branchId, tableId })
    _tableCache.set(tableId, fresh)
    return fresh
  }
  /**
   * Drop the cached preview for a table. Pass a tableId to drop just that
   * entry (used by realtime order/table events) or omit to drop everything
   * (used after a successful checkout).
   */
  function clearTableCache(tableId?: string) {
    if (tableId) _tableCache.delete(tableId)
    else _tableCache.clear()
  }

  async function executeCheckout(params: {
    orderId: string
    paymentMethod: string
    paymentRef?: string
    voucherCode?: string
    pointsToRedeem?: number
    serviceChargePct?: number
    vatPct?: number
    branchId: string
    cashierId: string
  }): Promise<CheckoutResult> {
    loading.value = true
    error.value = null
    try {
      const { data, error: err } = await supabase.rpc('process_checkout', {
        p_order_id: params.orderId,
        p_branch_id: params.branchId,
        p_cashier_id: params.cashierId,
        p_payment_method: params.paymentMethod,
        p_voucher_code: params.voucherCode || null,
        p_points_to_use: params.pointsToRedeem || 0,
      })
      if (err) throw err
      checkoutResult.value = data as CheckoutResult
      // After successful checkout, drop the cached preview for this table
      // (the table's bill is now Paid — preview is stale).
      _tableCache.clear()
      return data as CheckoutResult
    } catch (e: any) {
      error.value = e.message || String(e)
      throw e
    } finally {
      loading.value = false
    }
  }

  async function checkout(params: any): Promise<CheckoutResult | null> {
    if (!params?.branchId || !params?.cashierId || !params?.paymentMethod) {
      throw new Error('checkout requires branchId, cashierId and paymentMethod')
    }
    return executeCheckout({
      orderId: params.orderId,
      branchId: params.branchId,
      cashierId: params.cashierId,
      paymentMethod: params.paymentMethod,
      voucherCode: params.voucherCode,
      pointsToRedeem: params.pointsToRedeem,
      paymentRef: params.paymentRef,
      serviceChargePct: params.serviceChargePct,
      vatPct: params.vatPct,
    })
  }

  function printReceipt(result: CheckoutResult): void {
    console.log('Printing receipt for', result.invoice_number)
    window.print()
  }

  return {
    checkoutResult,
    loading,
    error,
    previewCheckout,
    previewTableSummary,
    clearTableCache,
    executeCheckout,
    checkout,
    printReceipt,
  }
}

import { ref } from 'vue'
import { supabase } from '@/lib/supabase'
import { useBranch, throwBranchGuard } from './useBranch'
import type { MenuCategory, MenuItem, Package as PackageRow } from '@/types/database'

export function useMenu() {
  const { activeBranchId } = useBranch()
  const loading = ref(false)
  const error = ref<string | null>(null)

  async function getCategories(branchOverride?: string): Promise<MenuCategory[]> {
    loading.value = true
    error.value = null
    const { data, error: err } = await supabase.rpc('customer_list_menu_categories', {
      p_branch_id: branchOverride ?? activeBranchId.value ?? throwBranchGuard(),
    })
    loading.value = false
    if (err) {
      error.value = err.message
      throw err
    }
    return (data ?? []) as MenuCategory[]
  }

  async function getItems(categoryId?: string, branchOverride?: string): Promise<MenuItem[]> {
    loading.value = true
    error.value = null
    const { data, error: err } = await supabase.rpc('customer_list_menu_items', {
      p_branch_id: branchOverride ?? activeBranchId.value ?? throwBranchGuard(),
      p_category_id: categoryId ?? null,
    })
    loading.value = false
    if (err) {
      error.value = err.message
      throw err
    }
    return (data ?? []) as MenuItem[]
  }

  async function getPackages(): Promise<PackageRow[]> {
    loading.value = true
    error.value = null
    const { data, error: err } = await supabase.rpc('hall_list_packages', {
      p_branch_id: activeBranchId.value ?? throwBranchGuard(),
    })
    loading.value = false
    if (err) {
      error.value = err.message
      throw err
    }
    return (data ?? []) as PackageRow[]
  }

  async function upsertItem(item: Partial<MenuItem>): Promise<MenuItem> {
    const payload = { ...item, branch_id: activeBranchId.value }
    const { data, error: err } = await supabase
      .from('menu_items')
      .upsert(payload)
      .select('*')
      .single<MenuItem>()
    if (err) throw err
    return data!
  }

  return { loading, error, getCategories, getItems, getPackages, upsertItem }
}

